import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

// 定义女性角色的通用结构
const FemaleRoleSchema = z.object({
  对user好感度: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),
  着装: z.object({
    上装: z.string().prefault(''),
    下装: z.string().prefault(''),
    内衣: z.string().prefault(''),
    袜子: z.string().prefault(''),
    鞋子: z.string().prefault(''),
    饰品: z.string().prefault(''),
  }).prefault({}),
  性爱痕迹: z.string().describe('详细描述身上的吻痕、体液残留、红肿等').prefault('无'),
  心里话: z.string().describe('当前时刻最真实的内心独白').prefault(''),
}).prefault({});

export const Schema = z.object({
  // 系统变量
  世界: z.object({
    时间: z.string().prefault(''),
    地点: z.string().prefault(''),
  }).prefault({}),

  // 角色变量
  王鹏: z.object({
    道心圆满值: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),
  }).prefault({}),

  // 女性角色
  姬扶摇: FemaleRoleSchema,
  慕凤鸾: FemaleRoleSchema,
  萧幼薇: FemaleRoleSchema,
})
// 添加全局逻辑约束
.transform(data => {
  // 检查所有女性角色的好感度是否都达到100
  const isAllMaxAffection =
    data.姬扶摇.对user好感度 >= 100 &&
    data.慕凤鸾.对user好感度 >= 100 &&
    data.萧幼薇.对user好感度 >= 100;

  // 如果未全部拉满，王鹏的道心圆满值被限制在99以下
  if (!isAllMaxAffection && data.王鹏.道心圆满值 >= 100) {
    data.王鹏.道心圆满值 = 99;
  }

  return data;
});

$(() => {
  registerMvuSchema(Schema);
})
